import { useRef, useCallback, RefObject } from 'react';

type SwipeGestureOptionsT = {
  onSwipeDown: () => void;
  threshold?: number;
  enabled?: boolean;
};

type UseSwipeGestureReturnT = {
  ref: RefObject<HTMLDivElement>;
  isDragging: boolean;
  dragOffset: number;
};

export const useSwipeGesture = ({
  onSwipeDown,
  threshold = 100,
  enabled = true,
}: SwipeGestureOptionsT): UseSwipeGestureReturnT => {
  const ref = useRef<HTMLDivElement>(null);
  const startY = useRef<number>(0);
  const currentY = useRef<number>(0);
  const isDragging = useRef<boolean>(false);
  const dragOffset = useRef<number>(0);

  const handleTouchStart = useCallback(
    (e: TouchEvent) => {
      if (!enabled) return;

      const touch = e.touches[0];
      if (!touch) return;

      startY.current = touch.clientY;
      currentY.current = touch.clientY;
      isDragging.current = true;
      dragOffset.current = 0;

      if (ref.current) {
        ref.current.style.transition = 'none';
      }
    },
    [enabled],
  );

  const handleTouchMove = useCallback(
    (e: TouchEvent) => {
      if (!enabled || !isDragging.current) return;

      const touch = e.touches[0];
      if (!touch) return;

      currentY.current = touch.clientY;
      const deltaY = currentY.current - startY.current;

      if (deltaY > 0) {
        dragOffset.current = deltaY;

        if (ref.current) {
          ref.current.style.transform = `translateY(${deltaY}px)`;
        }

        e.preventDefault();
      }
    },
    [enabled],
  );

  const handleTouchEnd = useCallback(() => {
    if (!enabled || !isDragging.current) return;

    const deltaY = dragOffset.current;

    if (ref.current) {
      ref.current.style.transition = '';
      ref.current.style.transform = '';
    }

    if (deltaY > threshold) {
      onSwipeDown();
    }

    isDragging.current = false;
    dragOffset.current = 0;
    startY.current = 0;
    currentY.current = 0;
  }, [enabled, threshold, onSwipeDown]);

  const attachListeners = useCallback(
    (element: HTMLDivElement | null) => {
      if (!element) return;

      element.addEventListener('touchstart', handleTouchStart, {
        passive: false,
      });
      element.addEventListener('touchmove', handleTouchMove, {
        passive: false,
      });
      element.addEventListener('touchend', handleTouchEnd);

      return () => {
        element.removeEventListener('touchstart', handleTouchStart);
        element.removeEventListener('touchmove', handleTouchMove);
        element.removeEventListener('touchend', handleTouchEnd);
      };
    },
    [handleTouchStart, handleTouchMove, handleTouchEnd],
  );

  const setRef = useCallback(
    (element: HTMLDivElement | null) => {
      if (ref.current) {
        const cleanup = attachListeners(null);
        cleanup?.();
      }

      ref.current = element;

      if (element) {
        attachListeners(element);
      }
    },
    [attachListeners],
  );

  (ref as any).current = setRef;

  return {
    ref,
    isDragging: isDragging.current,
    dragOffset: dragOffset.current,
  };
};

